<?php declare(strict_types=1);
namespace SkyFi\System\Repositories;
use SkyFi\System\Contracts\SystemSettingsRepositoryContract;
final class PdoSystemSettingsRepository extends PdoSystemRepository implements SystemSettingsRepositoryContract { private array $json=['password_policy','mfa_policy','file_upload_limits','email_settings','sms_provider_settings','cache_settings','logging_settings']; private array $allowed=['application_name','environment_name','maintenance_mode','maintenance_message','session_timeout_minutes','password_policy','mfa_policy','file_upload_limits','email_settings','sms_provider_settings','cache_settings','logging_settings']; public function first(): array { return $this->singleton('system_settings', self::defaults(), $this->json); } public function update(array $data, ?int $userId=null): array { return $this->updateSingleton('system_settings',$data,self::defaults(),$this->allowed,$this->json,$userId); } public function dashboard(): array { return ['active_branches'=>(int)$this->pdo->query("SELECT COUNT(*) FROM branches WHERE status='active' AND deleted_at IS NULL")->fetchColumn(),'active_departments'=>(int)$this->pdo->query("SELECT COUNT(*) FROM departments WHERE status='active' AND deleted_at IS NULL")->fetchColumn()]; } public static function defaults(): array { return ['application_name'=>'SkyFi ISP Management','environment_name'=>'production','maintenance_mode'=>0,'session_timeout_minutes'=>60,'password_policy'=>['min_length'=>12,'require_uppercase'=>true,'require_lowercase'=>true,'require_number'=>true,'require_symbol'=>true],'mfa_policy'=>['enabled'=>false,'status'=>'placeholder'],'file_upload_limits'=>['max_mb'=>5,'allowed_mime_types'=>['image/png','image/jpeg','image/webp','image/x-icon']],'email_settings'=>['enabled'=>false,'provider'=>'smtp'],'sms_provider_settings'=>['enabled'=>false,'status'=>'placeholder'],'cache_settings'=>['driver'=>'file','ttl_seconds'=>300],'logging_settings'=>['level'=>'info']]; }}
